from __future__ import annotations

import base64
import gzip
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
ASSETS = ROOT / "src" / "renderer" / "assets"
BUILD = ROOT / "scripts" / "build-vercel.cjs"

JS_GZIP_B64 = ""
CSS_GZIP_B64 = ""


def decode(value: str) -> str:
    return gzip.decompress(base64.b64decode(value)).decode("utf-8")


def replace_once(text: str, old: str, new: str, label: str) -> str:
    count = text.count(old)
    if count != 1:
        raise SystemExit(f"{label}: expected one occurrence, found {count}")
    return text.replace(old, new, 1)


ASSETS.mkdir(parents=True, exist_ok=True)
(ASSETS / "media-emoji-upgrade.js").write_text(decode(JS_GZIP_B64), encoding="utf-8")
(ASSETS / "media-emoji-upgrade.css").write_text(decode(CSS_GZIP_B64), encoding="utf-8")

build = BUILD.read_text(encoding="utf-8")
build = replace_once(build, 'const BRAND_VERSION = "26";', 'const BRAND_VERSION = "27";', "asset version")
build = replace_once(
    build,
    '      `    <link rel="stylesheet" href="/assets/rich-composer.css?v=${BRAND_VERSION}" />`\n',
    '      `    <link rel="stylesheet" href="/assets/rich-composer.css?v=${BRAND_VERSION}" />`,\n'
    '      `    <link rel="stylesheet" href="/assets/media-emoji-upgrade.css?v=${BRAND_VERSION}" />`\n',
    "media css injection",
)
build = replace_once(
    build,
    '      `    <script src="/assets/rich-composer.js?v=${BRAND_VERSION}"></script>`\n',
    '      `    <script src="/assets/rich-composer.js?v=${BRAND_VERSION}"></script>`,\n'
    '      `    <script src="/assets/media-emoji-upgrade.js?v=${BRAND_VERSION}"></script>`\n',
    "media js injection",
)
BUILD.write_text(build, encoding="utf-8")
